import{_ as o,c as a,o as l,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"计划批注: 四种注释类型 | plannotator","description":"掌握 Plannotator 四种注释类型的使用方法。学习删除、替换、插入、评论的添加技巧，支持 type-to-comment 快捷输入和图片附件，提升计划评审效率。","frontmatter":{"title":"计划批注: 四种注释类型 | plannotator","sidebarTitle":"添加四种注释类型","subtitle":"计划批注: 四种注释类型","description":"掌握 Plannotator 四种注释类型的使用方法。学习删除、替换、插入、评论的添加技巧，支持 type-to-comment 快捷输入和图片附件，提升计划评审效率。","tags":["计划注释","注释类型","删除","替换","插入","评论","type-to-comment","图片附件"],"prerequisite":["platforms-plan-review-basics"],"order":2},"headers":[],"relativePath":"zh/backnotprop/plannotator/platforms/plan-review-annotations/index.md","filePath":"zh/backnotprop/plannotator/platforms/plan-review-annotations/index.md"}'),i={name:"zh/backnotprop/plannotator/platforms/plan-review-annotations/index.md"};function n(s,t,r,p,d,c){return l(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="添加计划注释-掌握四种注释类型" tabindex="-1">添加计划注释：掌握四种注释类型 <a class="header-anchor" href="#添加计划注释-掌握四种注释类型" aria-label="Permalink to &quot;添加计划注释：掌握四种注释类型&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>✅ 选中计划文本，添加四种不同类型的注释（删除、替换、插入、评论）</li><li>✅ 使用 type-to-comment 快捷键直接输入评论</li><li>✅ 在注释中附加图片（参考图、截图等）</li><li>✅ 理解每种注释类型的含义和使用场景</li><li>✅ 查看注释导出后的 Markdown 格式</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p><strong>问题 1</strong>：知道要删除某段内容，但选中文本后不知道点击哪个按钮。</p><p><strong>问题 2</strong>：想替换一段代码，但工具栏里只有&quot;删除&quot;和&quot;评论&quot;，没有&quot;替换&quot;选项。</p><p><strong>问题 3</strong>：选中多行文本想直接输入评论，每次都要先点击&quot;Comment&quot;按钮，效率低。</p><p><strong>问题 4</strong>：想给某段代码附加参考图，但不知道怎么上传图片。</p><p><strong>Plannotator 能帮你</strong>：</p><ul><li>清晰的按钮图标，一眼看出删除、替换、插入、评论的区别</li><li>type-to-comment 快捷键，直接输入无需点击按钮</li><li>注释中支持图片附件，方便添加参考图</li><li>注释自动转换为结构化 Markdown，AI 准确理解</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p><strong>使用场景</strong>：</p><ul><li>评审 AI 生成的实施计划，需要精确反馈修改意见</li><li>某段内容不需要（删除）</li><li>某段内容需要改成另一种写法（替换）</li><li>某段内容后面需要补充说明（插入）</li><li>对某段内容有疑问或建议（评论）</li></ul><p><strong>不适用场景</strong>：</p><ul><li>只是整体批准或拒绝计划（无需注释，直接决策即可）</li><li>已经在评审代码变更（使用代码评审功能）</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p><strong>前置条件</strong>：</p><ul><li>✅ 已完成 <a href="./../plan-review-basics/">计划评审基础</a> 教程</li><li>✅ 了解如何触发 Plannotator 计划评审界面</li></ul><p><strong>本课假设</strong>：</p><ul><li>你已经打开了 Plannotator 计划评审页面</li><li>页面中显示了一个 AI 生成的 Markdown 计划</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="注释类型详解" tabindex="-1">注释类型详解 <a class="header-anchor" href="#注释类型详解" aria-label="Permalink to &quot;注释类型详解&quot;">​</a></h3><p>Plannotator 支持四种计划注释类型（外加一种全局评论）：</p><table tabindex="0"><thead><tr><th>注释类型</th><th>图标</th><th>用途</th><th>是否需要输入内容</th></tr></thead><tbody><tr><td><strong>删除 (DELETION)</strong></td><td>🗑️</td><td>标记此内容应从计划中移除</td><td>❌ 不需要</td></tr><tr><td><strong>评论 (COMMENT)</strong></td><td>💬</td><td>对选中内容提出问题或建议</td><td>✅ 需要输入评论</td></tr><tr><td><strong>替换 (REPLACEMENT)</strong></td><td>通过评论实现</td><td>用新内容替换选中内容</td><td>✅ 需要输入新内容</td></tr><tr><td><strong>插入 (INSERTION)</strong></td><td>通过评论实现</td><td>在选中内容后插入新内容</td><td>✅ 需要输入新内容</td></tr><tr><td><strong>全局评论 (GLOBAL_COMMENT)</strong></td><td>页面底部输入框</td><td>对整个计划提出反馈</td><td>✅ 需要输入评论</td></tr></tbody></table><p><strong>为什么替换和插入没有独立按钮？</strong></p><p>因为从源码实现来看，替换和插入本质上是特殊的评论类型（<code>packages/ui/utils/parser.ts:287-296</code>）：</p><ul><li><strong>替换</strong>：评论内容作为替换的新文本</li><li><strong>插入</strong>：评论内容作为插入的新文本</li></ul><p>它们都使用 <strong>评论 (COMMENT)</strong> 按钮创建，区别在于你如何描述意图。</p><h3 id="工具栏工作流程" tabindex="-1">工具栏工作流程 <a class="header-anchor" href="#工具栏工作流程" aria-label="Permalink to &quot;工具栏工作流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>选中文本 → 工具栏弹出（菜单步骤）</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ├── 点击 Delete → 立即创建删除注释</span></span>
<span class="line"><span>                 ├── 点击 Comment → 进入输入步骤 → 输入内容 → 保存</span></span>
<span class="line"><span>                 └── 直接输入字符 → type-to-comment → 自动进入输入步骤</span></span></code></pre></div><p><strong>两个步骤的区别</strong>：</p><ul><li><strong>菜单步骤</strong>：选择操作类型（删除、评论、取消）</li><li><strong>输入步骤</strong>：输入评论内容或附加图片（从评论/替换/进入）</li></ul><h3 id="type-to-comment-快捷键" tabindex="-1">type-to-comment 快捷键 <a class="header-anchor" href="#type-to-comment-快捷键" aria-label="Permalink to &quot;type-to-comment 快捷键&quot;">​</a></h3><p>这是提升效率的关键功能。当你选中一段文本后，<strong>直接开始打字</strong>（不需要点击任何按钮），工具栏会自动：</p><ol><li>切换到&quot;评论&quot;模式</li><li>将你输入的第一个字符放入输入框</li><li>光标自动定位到输入框末尾</li></ol><p>源码实现位置：<code>packages/ui/components/AnnotationToolbar.tsx:127-147</code></p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-启动计划评审" tabindex="-1">第 1 步：启动计划评审 <a class="header-anchor" href="#第-1-步-启动计划评审" aria-label="Permalink to &quot;第 1 步：启动计划评审&quot;">​</a></h3><p><strong>为什么</strong> 需要一个实际的计划来练习添加注释。</p><p><strong>操作</strong></p><p>在 Claude Code 或 OpenCode 中触发计划评审：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Claude Code 示例：让 AI 生成计划后，它会调用 ExitPlanMode</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;请生成一个用户认证功能的实施计划&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等待 AI 完成计划，Plannotator 会自动在浏览器中打开</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>浏览器打开计划评审页面</li><li>页面显示一个 Markdown 格式的实施计划</li></ul><h3 id="第-2-步-添加删除注释" tabindex="-1">第 2 步：添加删除注释 <a class="header-anchor" href="#第-2-步-添加删除注释" aria-label="Permalink to &quot;第 2 步：添加删除注释&quot;">​</a></h3><p><strong>为什么</strong> 删除注释用于标记不希望出现在最终计划中的内容。</p><p><strong>操作</strong></p><ol><li>在计划中找到你不需要的段落（例如某个不相关的功能描述）</li><li>鼠标选中文本</li><li>工具栏自动弹出，点击 <strong>删除按钮（🗑️）</strong></li></ol><p><strong>你应该看到</strong>：</p><ul><li>被选中的文本显示为删除样式（通常是删除线或红色背景）</li><li>工具栏自动关闭</li></ul><div class="tip custom-block"><p class="custom-block-title">删除注释的特点</p><p>删除注释<strong>不需要输入任何内容</strong>。点击删除按钮后，注释立即创建完成。</p></div><h3 id="第-3-步-使用-type-to-comment-添加评论" tabindex="-1">第 3 步：使用 type-to-comment 添加评论 <a class="header-anchor" href="#第-3-步-使用-type-to-comment-添加评论" aria-label="Permalink to &quot;第 3 步：使用 type-to-comment 添加评论&quot;">​</a></h3><p><strong>为什么</strong> 评论是最常用的注释类型，type-to-comment 能让你少点一次按钮。</p><p><strong>操作</strong></p><ol><li>在计划中选中文本（例如某个函数名或描述）</li><li><strong>不要点击任何按钮，直接开始打字</strong></li><li>输入你的评论内容（例如：&quot;这个函数名不够清晰&quot;）</li><li>按 <code>Enter</code> 键保存，或点击 <strong>Save</strong> 按钮</li></ol><p><strong>你应该看到</strong>：</p><ul><li>工具栏自动切换到输入框模式</li><li>你输入的第一个字符已经在输入框中</li><li>光标自动定位到输入框末尾</li><li>按 <code>Enter</code> 后，选中的文本显示为评论样式（通常是黄色背景）</li></ul><div class="tip custom-block"><p class="custom-block-title">type-to-comment 的快捷键</p><ul><li><code>Enter</code>：保存注释（如果输入框有内容）</li><li><code>Shift + Enter</code>：换行（输入多行评论时使用）</li><li><code>Escape</code>：取消输入，返回菜单步骤</li></ul></div><h3 id="第-4-步-添加替换注释" tabindex="-1">第 4 步：添加替换注释 <a class="header-anchor" href="#第-4-步-添加替换注释" aria-label="Permalink to &quot;第 4 步：添加替换注释&quot;">​</a></h3><p><strong>为什么</strong> 替换注释用于用新内容替换选中内容，AI 会根据你的注释修改计划。</p><p><strong>操作</strong></p><ol><li>在计划中选中文本（例如 &quot;使用 JWT token 进行认证&quot;）</li><li>使用 type-to-comment 或点击评论按钮</li><li>在输入框中输入新的内容（例如：&quot;使用 session cookie 进行认证&quot;）</li><li>按 <code>Enter</code> 保存</li></ol><p><strong>你应该看到</strong>：</p><ul><li>选中的文本显示为评论样式</li><li>注释侧边栏中显示你的评论内容</li></ul><p><strong>导出后的格式</strong>（<code>packages/ui/utils/parser.ts:292-296</code>）：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 1. Change this</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**From:**</span></span></code></pre></div><p>使用 JWT token 进行认证</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>**To:**</span></span></code></pre></div><p>使用 session cookie 进行认证</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">替换与删除的区别</p><ul><li><strong>删除</strong>：直接移除内容，不需要说明理由</li><li><strong>替换</strong>：用新内容替换旧内容，需要指定新内容</li></ul></div><h3 id="第-5-步-添加插入注释" tabindex="-1">第 5 步：添加插入注释 <a class="header-anchor" href="#第-5-步-添加插入注释" aria-label="Permalink to &quot;第 5 步：添加插入注释&quot;">​</a></h3><p><strong>为什么</strong> 插入注释用于在选中内容后补充说明或代码片段。</p><p><strong>操作</strong></p><ol><li>在计划中选中文本（例如函数签名的末尾）</li><li>使用 type-to-comment 或点击评论按钮</li><li>在输入框中输入要插入的内容（例如：&quot;，需要处理认证失败的情况&quot;）</li><li>按 <code>Enter</code> 保存</li></ol><p><strong>你应该看到</strong>：</p><ul><li>选中的文本显示为评论样式</li><li>注释侧边栏中显示你的评论</li></ul><p><strong>导出后的格式</strong>（<code>packages/ui/utils/parser.ts:287-290</code>）：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 1. Add this</span></span></code></pre></div><p>，需要处理认证失败的情况</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span></code></pre></div><h3 id="第-6-步-在注释中附加图片" tabindex="-1">第 6 步：在注释中附加图片 <a class="header-anchor" href="#第-6-步-在注释中附加图片" aria-label="Permalink to &quot;第 6 步：在注释中附加图片&quot;">​</a></h3><p><strong>为什么</strong> 有时候文字描述不够直观，需要附加参考图或截图。</p><p><strong>操作</strong></p><ol><li>选中任意文本，进入输入步骤（点击评论按钮或 type-to-comment）</li><li>在工具栏输入框旁边，点击 <strong>附件按钮（📎）</strong></li><li>选择要上传的图片（支持 PNG、JPEG、WebP 格式）</li><li>可以继续输入评论内容</li><li>按 <code>Enter</code> 保存</li></ol><p><strong>你应该看到</strong>：</p><ul><li>图片缩略图显示在输入框中</li><li>保存后，图片显示在注释侧边栏中</li></ul><div class="warning custom-block"><p class="custom-block-title">图片存储位置</p><p>上传的图片保存在本地 <code>/tmp/plannotator</code> 目录（源码位置：<code>packages/server/index.ts:163</code>）。如果清理临时文件，图片会丢失。</p></div><h3 id="第-7-步-添加全局评论" tabindex="-1">第 7 步：添加全局评论 <a class="header-anchor" href="#第-7-步-添加全局评论" aria-label="Permalink to &quot;第 7 步：添加全局评论&quot;">​</a></h3><p><strong>为什么</strong> 当你对整个计划有反馈（不是针对具体某段文本）时，使用全局评论。</p><p><strong>操作</strong></p><ol><li>在页面底部找到输入框（标签可能是 &quot;Add a general comment about the plan...&quot;）</li><li>输入你的评论内容</li><li>按 <code>Enter</code> 保存或点击发送按钮</li></ol><p><strong>你应该看到</strong>：</p><ul><li>评论出现在页面底部的全局评论区域</li><li>评论显示为独立卡片，不关联任何文本块</li></ul><div class="tip custom-block"><p class="custom-block-title">全局评论 vs 文本评论</p><ul><li><strong>全局评论</strong>：对整个计划的反馈，不关联具体文本（例如&quot;整个计划缺少性能考虑&quot;）</li><li><strong>文本评论</strong>：对某段文本的反馈，会高亮显示对应的文本</li></ul></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成上述步骤后，你应该：</p><ul><li>[ ] 成功添加了至少一个删除注释</li><li>[ ] 使用 type-to-comment 添加了评论</li><li>[ ] 添加了替换和插入注释</li><li>[ ] 在注释中附加了图片</li><li>[ ] 添加了全局评论</li><li>[ ] 在右侧侧边栏看到所有注释列表</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="坑-1-找不到-替换-按钮" tabindex="-1">坑 1：找不到&quot;替换&quot;按钮 <a class="header-anchor" href="#坑-1-找不到-替换-按钮" aria-label="Permalink to &quot;坑 1：找不到&quot;替换&quot;按钮&quot;">​</a></h3><p><strong>错误操作</strong>：</p><ul><li>选中文本后，工具栏只有 Delete 和 Comment，没有 Replace 或 Insert 按钮</li></ul><p><strong>正确做法</strong>：</p><ul><li>替换和插入通过 <strong>评论 (COMMENT)</strong> 按钮实现</li><li>在评论内容中描述你的意图（替换或插入）</li><li>AI 会根据评论内容理解你的意图</li></ul><h3 id="坑-2-type-to-comment-失效" tabindex="-1">坑 2：type-to-comment 失效 <a class="header-anchor" href="#坑-2-type-to-comment-失效" aria-label="Permalink to &quot;坑 2：type-to-comment 失效&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ol><li>没有选中文本</li><li>先点击了某个按钮，工具栏已进入输入步骤</li><li>输入了特殊键（<code>Ctrl</code>、<code>Alt</code>、<code>Escape</code> 等）</li></ol><p><strong>正确做法</strong>：</p><ol><li>先选中文本，确保工具栏显示在菜单步骤（有 Delete、Comment 按钮）</li><li>直接输入普通字符（字母、数字、标点）</li><li>不要按功能键</li></ol><h3 id="坑-3-图片上传后找不到" tabindex="-1">坑 3：图片上传后找不到 <a class="header-anchor" href="#坑-3-图片上传后找不到" aria-label="Permalink to &quot;坑 3：图片上传后找不到&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>图片保存在 <code>/tmp/plannotator</code> 目录</li><li>系统清理了临时文件</li></ul><p><strong>正确做法</strong>：</p><ul><li>如果需要长期保存图片，建议复制到项目目录</li><li>导出注释时，图片路径是绝对路径，确保其他工具可以访问</li></ul><h3 id="坑-4-按-enter-换行却保存了注释" tabindex="-1">坑 4：按 <code>Enter</code> 换行却保存了注释 <a class="header-anchor" href="#坑-4-按-enter-换行却保存了注释" aria-label="Permalink to &quot;坑 4：按 \`Enter\` 换行却保存了注释&quot;">​</a></h3><p><strong>错误操作</strong>：</p><ul><li>在输入框中想换行，直接按 <code>Enter</code>，结果注释被保存</li></ul><p><strong>正确做法</strong>：</p><ul><li>使用 <code>Shift + Enter</code> 换行</li><li><code>Enter</code> 键专用于保存注释</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p><strong>四种注释类型</strong>：</p><ul><li><strong>删除 (DELETION)</strong>：标记不希望出现在计划中的内容</li><li><strong>替换 (REPLACEMENT)</strong>：用新内容替换选中内容（通过评论实现）</li><li><strong>插入 (INSERTION)</strong>：在选中内容后补充内容（通过评论实现）</li><li><strong>评论 (COMMENT)</strong>：对选中内容提出问题或建议</li><li><strong>全局评论 (GLOBAL_COMMENT)</strong>：对整个计划的反馈</li></ul><p><strong>关键操作</strong>：</p><ul><li>选中 → 工具栏弹出 → 选择操作类型</li><li>type-to-comment：直接输入字符，自动进入评论模式</li><li><code>Shift + Enter</code>：换行；<code>Enter</code>：保存</li><li>附件按钮：上传图片到注释</li></ul><p><strong>注释导出格式</strong>：</p><ul><li>删除：<code>## Remove this</code> + 原文本</li><li>插入：<code>## Add this</code> + 新文本</li><li>替换：<code>## Change this</code> + From/To 对比</li><li>评论：<code>## Feedback on: &quot;...&quot;</code> + 评论内容</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../plan-review-images/">添加图像标注</a></strong>。</p><p>你会学到：</p><ul><li>如何在计划评审中附加图像</li><li>使用画笔、箭头、圆形工具进行标注</li><li>标注图像作为参考反馈</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>注释类型枚举定义</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L7" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-7</td></tr><tr><td>Annotation 接口</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L11-L33" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>11-33</td></tr><tr><td>注释工具栏组件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L29-L272" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></td><td>29-272</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>注释导出格式化</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/parser.ts#L246-L323" target="_blank" rel="noreferrer"><code>packages/ui/utils/parser.ts</code></a></td><td>246-323</td></tr><tr><td>Markdown 解析为 Blocks</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/parser.ts#L70-L244" target="_blank" rel="noreferrer"><code>packages/ui/utils/parser.ts</code></a></td><td>70-244</td></tr><tr><td>Viewer 组件（文本选择处理）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L66-L350" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>66-350</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>AnnotationType.DELETION = &#39;DELETION&#39;</code>：删除注释类型</li><li><code>AnnotationType.INSERTION = &#39;INSERTION&#39;</code>：插入注释类型</li><li><code>AnnotationType.REPLACEMENT = &#39;REPLACEMENT&#39;</code>：替换注释类型</li><li><code>AnnotationType.COMMENT = &#39;COMMENT&#39;</code>：评论注释类型</li><li><code>AnnotationType.GLOBAL_COMMENT = &#39;GLOBAL_COMMENT&#39;</code>：全局评论类型</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>exportDiff(blocks, annotations)</code>：将注释导出为 Markdown 格式，包含 From/To 对比</li><li><code>parseMarkdownToBlocks(markdown)</code>：将 Markdown 解析为线性 Block 数组</li><li><code>createAnnotationFromSource()</code>：从文本选择创建 Annotation 对象</li></ul></details>`,131)])])}const u=o(i,[["render",n]]);export{g as __pageData,u as default};
